package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_callsTypeAdaptersJsonElementWrite() throws Exception {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> mockedTypeAdapters = Mockito.mockStatic(TypeAdapters.class)) {
      // Use reflection to get the JSON_ELEMENT field type (TypeAdapter<JsonElement>)
      java.lang.reflect.Field jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
      jsonElementField.setAccessible(true);
      Class<?> typeAdapterClass = jsonElementField.getType();

      // Create a mock of the TypeAdapter<JsonElement> type
      Object jsonElementAdapterMock = mock(typeAdapterClass);

      // Mock the static field JSON_ELEMENT to return our mock
      mockedTypeAdapters.when(() -> jsonElementField.get(null)).thenReturn(jsonElementAdapterMock);

      // Use reflection to get the write method from the TypeAdapter class
      java.lang.reflect.Method writeMethod = typeAdapterClass.getMethod("write", JsonWriter.class, JsonElement.class);

      // Stub the write method on the mock using Mockito's doAnswer with reflection invocation
      doAnswer(invocation -> {
        // do nothing
        return null;
      }).when(jsonElementAdapterMock).getClass().getMethod("write", JsonWriter.class, JsonElement.class).invoke(jsonElementAdapterMock, writer, element);

      // Instead of above, we need to use Mockito's doNothing().when(mock).write(...) but the mock is of Object type
      // So use Mockito's "mockito-inline" or use a cast proxy to the interface/class with write method.
      // Better: cast to the right type to enable Mockito to find the write method:
      Object typedMock = jsonElementAdapterMock;
      // Cast the mock to the TypeAdapter type using a dynamic proxy is complicated.
      // Instead, use Mockito's withSettings().defaultAnswer() to create the mock with the right type:
      // But since we already created the mock, we can use Mockito's "mock" with the class and cast.

      // So let's recreate the mock properly:
      Object typedAdapterMock = mock(typeAdapterClass);
      mockedTypeAdapters.when(() -> jsonElementField.get(null)).thenReturn(typedAdapterMock);

      // Now stub the write method on typedAdapterMock
      // We need to cast typedAdapterMock to the typeAdapterClass to let Mockito find the method
      // But Java does not allow direct cast to Class<?> at compile time.
      // So use a helper interface:

      // Use reflection to get the write method again
      writeMethod = typeAdapterClass.getMethod("write", JsonWriter.class, JsonElement.class);
      // Use Mockito's doNothing().when(typedAdapterMock).write(writer, element);
      // But typedAdapterMock is Object, so use Mockito's doNothing().when() with reflection proxy:

      // Use Mockito's doNothing().when(typedAdapterMock).write(writer, element) via reflection proxy
      // Use Mockito's "mockito-inline" to allow mocking final classes/methods.

      // Alternatively, use Mockito's "mock" with the class and cast:
      Object adapterMock = typedAdapterMock;
      // Use Mockito's verify with reflection:
      // Call the method under test
      Streams.write(element, writer);

      // Verify the write method was called on adapterMock via reflection
      // Use Mockito.verify(adapterMock).write(writer, element);
      // But adapterMock is Object, so use Mockito.verify(adapterMock) with reflection:
      // Use Mockito.verify(adapterMock).write(writer, element);
      // So cast adapterMock to typeAdapterClass via a proxy:

      // Use Mockito's verify with reflection:
      verify(adapterMock, times(1)).getClass().getMethod("write", JsonWriter.class, JsonElement.class).invoke(adapterMock, writer, element);
